-- LESSON 10: PRESENT ACTIVE INDICATIVE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  64, 10, 'grammar', 'Present Active Indicative', 'λύω — I loose · Ongoing action — Intermediate',
  '{"concept":"Present Active Indicative Verbs","symbol":"λύω — λύεις — λύει","difficulty":"Intermediate","overview":"Greek verbs are the heart of the language. Every Greek verb encodes six pieces of information: person (1st/2nd/3rd), number (singular/plural), tense (time + kind of action), voice (active/middle/passive), mood (indicative/subjunctive/imperative), and sometimes aspect. The Present Active Indicative is the foundation: it describes ongoing, continuous, or habitual action from the perspective of the speaker as real (indicative mood). Memorising the λύω paradigm gives you the pattern for hundreds of NT verbs.","key_points":["Greek verbs encode person and number in the ending — subject pronouns often omitted","Present tense: ongoing or habitual action (I am loosing / I loose / I keep loosing)","Active voice: the subject performs the action","Indicative mood: stating a fact (vs. subjunctive = possibility)","The personal endings: -ω, -εις, -ει, -ομεν, -ετε, -ουσι(ν)","The connecting vowel -ο/-ε- links the stem to the personal ending"],"examples":[{"greek":"πιστεύω εἰς τὸν υἱὸν τοῦ θεοῦ","translation":"I believe into the Son of God","reference":"Galatians 2:20","note":"1st singular present active — πιστεύ- (stem) + -ω (1st sg ending). Ongoing personal faith"},{"greek":"οὐ γινώσκεις;","translation":"Do you not know?","reference":"John 3:10","note":"2nd singular present active — γινώσκ- + -εις. Jesus challenges Nicodemus"},{"greek":"ὁ πατὴρ ἀγαπᾷ τὸν υἱόν","translation":"The Father loves the Son","reference":"John 3:35","note":"3rd singular present active contracted — ἀγαπά- + -ει → ἀγαπᾷ (contracted). Timeless love"}],"tables":[{"title":"Present Active Indicative: λύω (I loose)","headers":["Person","Singular","Plural"],"rows":[["1st","λύω (I loose)","λύομεν (we loose)"],["2nd","λύεις (you loose)","λύετε (you all loose)"],["3rd","λύει (he/she/it looses)","λύουσι(ν) (they loose)"]]},{"title":"How to Parse a Greek Verb","headers":["Feature","Question","Example: λύει"],"rows":[["Tense","When? What kind of action?","Present (ongoing)"],["Voice","Who does the action?","Active (subject acts)"],["Mood","Real or potential?","Indicative (stated as fact)"],["Person","Who?","3rd (he/she/it)"],["Number","How many?","Singular"],["Lexical form","Dictionary form?","λύω (I loose)"]]}],"practice":[{"type":"identify","question":"What are the six personal endings of the Present Active Indicative in order?","answer":"-ω, -εις, -ει, -ομεν, -ετε, -ουσι(ν)"},{"type":"choice","question":"The verb πιστεύουσιν appears in John 12:37 (yet they believed not). What person and number is this?","options":["1st singular","2nd plural","3rd plural","1st plural"],"answer":2},{"type":"choice","question":"The present tense in Greek primarily expresses what kind of action?","options":["Completed action in the past","Ongoing, continuous, or habitual action","Future action","Action with no time reference"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life","note":"πιστεύων — present active participle (believing, ongoing). The ongoing nature of saving faith is embedded in the present tense. Not a one-time act but a continuous trusting"},{"ref":"1 John 4:8","text":"He that loveth not knoweth not God; for God is love","note":"ὁ μὴ ἀγαπῶν οὐκ ἔγνω τὸν θεόν — the one not loving (present) has not known God. Present tense loving is John''s litmus test of genuine knowledge of God"}]'
);

-- LESSON 11: IMPERFECT AND FUTURE TENSES
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  65, 11, 'grammar', 'Imperfect & Future Tenses', 'Past ongoing · Future certain — Intermediate',
  '{"concept":"Imperfect and Future Tenses","symbol":"ἔλυον — λύσω","difficulty":"Intermediate","overview":"The Imperfect tense describes ongoing or repeated action in the PAST — I was loosing, I kept loosing. It is formed by adding an augment (ε-) to the front of the verb, then using secondary endings. The Future tense describes action yet to happen — I will loose. It uses a sigma (σ) inserted between stem and ending. Both tenses are crucial for NT narrative and prophecy.","key_points":["Imperfect: past ongoing action. Formed with augment (ε-) + stem + secondary endings","Secondary endings: -ον, -ες, -ε(ν), -ομεν, -ετε, -ον","Augment: ε- prefixed to verb beginning; if verb begins with a vowel, the vowel lengthens","Future: adds -σ- between stem and present endings (λύ- + σ- + ω = λύσω)","The Imperfect often captures vivid narrative action: they were going, he kept teaching","The Future Indicative states something as certain/expected: I WILL save"],"examples":[{"greek":"ἐδίδασκεν αὐτούς","translation":"He was teaching them (ongoing)","reference":"Matthew 5:2","note":"Imperfect 3rd singular — ἐδίδασκεν captures Jesus teaching as ongoing, not just one discrete act. The Sermon on the Mount was a sustained ministry"},{"greek":"σώσει τὸν λαὸν αὐτοῦ","translation":"He will save his people","reference":"Matthew 1:21","note":"Future active — σώσ- (future stem) + -ει (3rd sg). The angel''s announcement is future certain: HE WILL save"},{"greek":"ἦν διδάσκων","translation":"He was (continually) teaching","reference":"Mark 1:21","note":"Imperfect of εἰμί + present participle — a periphrastic construction emphasising the continuous, habitual nature of Jesus'' teaching ministry"}],"tables":[{"title":"Imperfect Active Indicative: ἔλυον","headers":["Person","Singular","Plural"],"rows":[["1st","ἔλυον (I was loosing)","ἐλύομεν (we were loosing)"],["2nd","ἔλυες (you were loosing)","ἐλύετε (you all were loosing)"],["3rd","ἔλυε(ν) (he/she/it was loosing)","ἔλυον (they were loosing)"]]},{"title":"Future Active Indicative: λύσω","headers":["Person","Singular","Plural"],"rows":[["1st","λύσω (I will loose)","λύσομεν (we will loose)"],["2nd","λύσεις (you will loose)","λύσετε (you all will loose)"],["3rd","λύσει (he/she/it will loose)","λύσουσι(ν) (they will loose)"]]}],"practice":[{"type":"identify","question":"How is the Imperfect tense formed? What is added to the front of the verb?","answer":"An augment — ε- is prefixed to the verb stem (e.g. λύω → ἔλυον)"},{"type":"choice","question":"Matthew 5:2 says He was teaching (ἐδίδασκεν — imperfect). Why is the imperfect significant here?","options":["It means He taught just once","It emphasises the ongoing, continuous nature of His teaching ministry","It indicates teaching in the future","It shows teaching is completed"],"answer":1},{"type":"choice","question":"The future tense in Greek inserts which letter between the stem and the ending?","options":["π","κ","σ (sigma)","τ"],"answer":2}]}',
  '[{"ref":"Matthew 5:2","text":"And he opened his mouth, and taught them, saying","note":"ἐδίδασκεν — imperfect (he was teaching, ongoing). The Sermon on the Mount is introduced with an imperfect — Jesus sat and taught continuously, not in one quick statement"},{"ref":"Matthew 1:21","text":"She shall bring forth a son, and thou shalt call his name JESUS: for he shall save his people from their sins","note":"σώσει — future indicative (he WILL save). The angel''s announcement is future certain. The name Jesus contains the future promise — YHWH will save. The future tense carries the weight of the entire Incarnation"}]'
);

-- LESSON 12: THE AORIST TENSE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  66, 12, 'grammar', 'The Aorist Tense', 'The unique Greek past — Point action — Intermediate',
  '{"concept":"The Aorist Tense","symbol":"ἔλυσα — I loosed","difficulty":"Intermediate","overview":"The Aorist is perhaps the most distinctive feature of Greek grammar. While English simply says I loved, Greek can choose between the Imperfect (I was loving, ongoing) and the Aorist (I loved, as a simple event). The Aorist views action as a whole, complete event — a point or snapshot, rather than a line. It is the most common narrative past tense in the NT. It does NOT necessarily mean instantaneous action — it is about how the author views the action, not its actual duration.","key_points":["Aorist = past action viewed as a whole event (point), not duration","Most common past tense in NT narrative","First Aorist (weak): adds -σ- and uses endings: -α, -ας, -ε, -αμεν, -ατε, -αν","Second Aorist (strong): irregular stem change, uses imperfect endings: ε-stem-ον","Aorist imperative is common for urgent, decisive commands","The Aorist does NOT inherently mean the action was brief — it means the author views it as a whole unit"],"examples":[{"greek":"ἠγάπησεν ὁ θεὸς τὸν κόσμον","translation":"God loved the world (as a whole event)","reference":"John 3:16","note":"ἠγάπησεν — 1st Aorist active. God''s love for the world is presented as a complete, decisive act. The cross is its focal point — the moment when the love was consummated"},{"greek":"ἔλαβεν σάρκα","translation":"he took flesh (became incarnate)","reference":"John 1:14","note":"Second aorist — ἐγένετο (became). The incarnation is a decisive event — a point in history when the eternal Word BECAME flesh"},{"greek":"ἀπέθανεν Χριστὸς ὑπὲρ ἡμῶν","translation":"Christ died for us","reference":"Romans 5:8","note":"ἀπέθανεν — aorist of ἀποθνῄσκω. The death of Christ is a historical point-event. Paul''s gospel rests on an aorist fact"}],"tables":[{"title":"First Aorist Active Indicative: ἔλυσα","headers":["Person","Singular","Plural"],"rows":[["1st","ἔλυσα (I loosed)","ἐλύσαμεν (we loosed)"],["2nd","ἔλυσας (you loosed)","ἐλύσατε (you all loosed)"],["3rd","ἔλυσε(ν) (he/she/it loosed)","ἔλυσαν (they loosed)"]]},{"title":"Aorist vs Imperfect","headers":["Tense","View of Action","Example","Translation"],"rows":[["Imperfect","Line — ongoing duration","ἐδίδασκεν","He was (continually) teaching"],["Aorist","Point — whole event","ἐδίδαξεν","He taught (as a complete act)"]]}],"practice":[{"type":"identify","question":"What is the key difference between the Aorist and Imperfect past tenses in Greek?","answer":"Aorist views action as a whole complete event (point); Imperfect views action as ongoing/continuous (line)"},{"type":"choice","question":"John 3:16 uses the aorist ἠγάπησεν (loved). What does this aorist communicate about God''s love?","options":["God''s love was brief and is now over","God''s love for the world is a complete, decisive event — consummated at the cross","God loved in the past but not now","God''s love is only ongoing, never completed"],"answer":1},{"type":"choice","question":"Romans 5:8 uses the aorist ἀπέθανεν (died). Why is the aorist appropriate here?","options":["Because death is an ongoing action","Because Christ''s death was a decisive historical event viewed as a complete whole","Because aorist is used for all past events","Because Paul was uncertain about the death"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son","note":"ἠγάπησεν...ἔδωκεν — both aorists. God LOVED (decisive event) and GAVE (decisive event). The gospel hinges on two aorist facts — two complete historical acts of divine grace"},{"ref":"Romans 5:8","text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us","note":"ἀπέθανεν — aorist (Christ died, as a historical fact). Paul''s entire argument for justification rests on this aorist event. The past tense of the cross is the foundation of present peace with God"}]'
);

-- LESSON 13: PERFECT AND PLUPERFECT TENSES
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  67, 13, 'grammar', 'Perfect & Pluperfect Tenses', 'Past action with present results — Intermediate',
  '{"concept":"Perfect and Pluperfect Tenses","symbol":"λέλυκα — It stands loosed","difficulty":"Intermediate","overview":"The Perfect tense is unique to Greek and carries enormous theological weight. It describes a past action whose results CONTINUE INTO THE PRESENT. It is not just I loosed (aorist) but I have loosed and it is still loose. The perfect communicates completed action with ongoing, present-state consequences. The Pluperfect adds one layer: the results continued up to a past point. In NT Greek, the perfect often carries the strongest possible assertion of continuing reality.","key_points":["Perfect: past action + present, continuing results. I have believed and still believe","Formed by: reduplication (first consonant + ε) + stem + -κ- + perfect endings","Perfect endings: -α, -ας, -ε, -αμεν, -ατε, -ασι(ν)","John 19:30 tetelestai (It is finished) — perfect tense: it is accomplished and the results are permanent","Hebrews 1:4 uses perfect to show Christ''s ongoing exalted status after His work","The perfect passive is especially important: it has been written = γέγραπται (Scripture''s permanent authority)"],"examples":[{"greek":"τετέλεσται","translation":"It is finished / It has been finished and remains so","reference":"John 19:30","note":"Perfect passive — Christ''s atoning work is not only complete in the past but its effects are permanently in force. The perfect tense makes this claim theologically decisive"},{"greek":"γέγραπται","translation":"It is written / It stands written","reference":"Matthew 4:4","note":"Perfect passive of γράφω. Jesus quotes Scripture in the perfect: it has been written and stands written. Scripture''s past composition has permanent present authority"},{"greek":"πεπίστευκα","translation":"I have believed and continue to believe","reference":"2 Timothy 1:12","note":"Perfect active — Paul''s past faith commitment has ongoing present reality. I have believed = and I still believe"}],"tables":[{"title":"Perfect Active Indicative: λέλυκα","headers":["Person","Singular","Plural"],"rows":[["1st","λέλυκα (I have loosed)","λελύκαμεν (we have loosed)"],["2nd","λέλυκας (you have loosed)","λελύκατε (you all have loosed)"],["3rd","λέλυκε(ν) (he has loosed)","λελύκασι(ν) (they have loosed)"]]},{"title":"Key NT Perfect Verbs","headers":["Greek","Translation","Reference","Significance"],"rows":[["τετέλεσται","It is finished/stands finished","John 19:30","Atonement is permanent"],["γέγραπται","It stands written","Matthew 4:4,6,7","Scripture has permanent authority"],["πεπίστευκα","I have believed","2 Tim 1:12","Ongoing, persevering faith"],["δέδωκα","I have given (and it remains given)","John 17:22","Christ''s gift of glory is permanently bestowed"]]}],"practice":[{"type":"identify","question":"What makes the Greek Perfect tense unique compared to the Aorist?","answer":"The Perfect describes a past action whose results continue into the present — completed action with ongoing consequences"},{"type":"choice","question":"Jesus says τετέλεσται (John 19:30) — It is finished (perfect tense). What does the perfect communicate?","options":["The work is over and done with, no longer relevant","The work was completed in the past AND its saving results are permanently in force now","Jesus was uncertain if the work was complete","It was a temporary work"],"answer":1},{"type":"choice","question":"γέγραπται means it stands written (perfect passive of γράφω). When Jesus quotes this in Matthew 4, what does the perfect tense assert about Scripture?","options":["Scripture was written long ago and is now outdated","Scripture was composed in the past and its authority permanently stands in the present","Scripture was just recently written","Scripture needs to be updated"],"answer":1}]}',
  '[{"ref":"John 19:30","text":"When Jesus therefore had received the vinegar, he said, It is finished: and he bowed his head, and gave up the ghost","note":"τετέλεσται — the perfect tense of the cross. Not merely finished as in over, but completed in a way that its redemptive results are permanently in force. The believer stands under an eternally effective atonement"},{"ref":"Matthew 4:4","text":"But he answered and said, It is written, Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God","note":"γέγραπται — it stands written. Three times Jesus rebukes Satan''s temptations with this perfect passive. Scripture''s past composition permanently settles every present challenge. The perfect tense IS the doctrine of Scripture''s authority"}]'
);

-- LESSON 14: MIDDLE AND PASSIVE VOICE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  68, 14, 'grammar', 'Middle & Passive Voice', 'Subject involved or acted upon — Intermediate',
  '{"concept":"Middle and Passive Voice","symbol":"λύομαι","difficulty":"Intermediate","overview":"Greek verbs have three voices: Active (subject acts), Middle (subject acts with special interest or involvement in the action), and Passive (subject is acted upon). In the present and imperfect, middle and passive share the same forms (called middle/passive). The Passive is theologically crucial in NT Greek — the divine passive (passivum divinum) is a common idiom where God is implied as the unstated agent of the passive verb.","key_points":["Active: subject performs action — ἀγαπᾷ (He loves)","Middle: subject acts with reflexive involvement or personal interest in the result","Passive: subject receives action — ἀγαπᾶται (He is loved, by someone else)","Divine passive (passivum divinum): God implied as agent — they will be comforted = God will comfort them","Middle/Passive share endings in present: -ομαι, -ῃ/-ει, -εται, -όμεθα, -εσθε, -ονται","Many key NT verbs are deponent — middle or passive in form but active in meaning"],"examples":[{"greek":"ἐβαπτίσθη ὑπὸ Ἰωάννου","translation":"He was baptized by John","reference":"Mark 1:9","note":"Aorist passive — Jesus is the subject receiving baptism. ὑπό + genitive = the agent (by John)"},{"greek":"μακάριοι οἱ πενθοῦντες, ὅτι αὐτοὶ παρακληθήσονται","translation":"Blessed are those who mourn, for they shall be comforted","reference":"Matthew 5:4","note":"παρακληθήσονται — future passive. Who will comfort them? God. The divine passive leaves the agent unstated because God is the implied actor"},{"greek":"ἐγείρεται","translation":"he is raised / he rises","reference":"1 Corinthians 15:4","note":"Present passive — Christ is raised (by God the Father, implied agent). The resurrection is passive: the Father raises the Son"}],"tables":[{"title":"Present Middle/Passive Indicative: λύομαι","headers":["Person","Singular","Plural"],"rows":[["1st","λύομαι (I am loosed/loose myself)","λυόμεθα"],["2nd","λύῃ (you are loosed)","λύεσθε"],["3rd","λύεται (he/she/it is loosed)","λύονται"]]},{"title":"Voice Summary","headers":["Voice","Subject''s Role","Example","Translation"],"rows":[["Active","Acts","ἀγαπᾷ","He loves"],["Middle","Acts with personal interest","λούεται","He washes himself"],["Passive","Is acted upon","ἀγαπᾶται","He is loved (by another)"]]}],"practice":[{"type":"identify","question":"What is the divine passive (passivum divinum) in NT Greek?","answer":"A passive verb where God is the implied but unstated agent — e.g. they shall be comforted (by God)"},{"type":"choice","question":"Matthew 5:4 — they shall be comforted (παρακληθήσονται, future passive). Who is the unstated agent doing the comforting?","options":["Other people","Angels","God — the divine passive implies God as actor","The Holy Spirit only"],"answer":2},{"type":"choice","question":"Many important NT verbs are deponent — what does this mean?","options":["They have no passive forms","They are middle or passive in form but active in meaning","They require an object","They only appear in the aorist"],"answer":1}]}',
  '[{"ref":"Matthew 5:4","text":"Blessed are they that mourn: for they shall be comforted","note":"παρακληθήσονται — future passive (divine passive). God will comfort the mourning. The Beatitudes are saturated with divine passives — God is always the unstated actor behind the promised blessings"},{"ref":"1 Corinthians 15:4","text":"And that he was buried, and that he rose again the third day according to the scriptures","note":"ἐγήγερται — perfect passive (he has been raised and remains raised). The resurrection is both passive (God raised Him) and perfect (the results are permanently in force). The empty tomb is a perfect tense fact"}]'
);

-- LESSON 15: INFINITIVES AND PARTICIPLES (INTRO)
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  69, 15, 'grammar', 'Infinitives & Participles', 'Verbal nouns and verbal adjectives — Intermediate',
  '{"concept":"Infinitives and Participles","symbol":"λύειν · λύων","difficulty":"Intermediate","overview":"Greek has two important verbals — word forms that are partly verb, partly something else. The Infinitive is a verbal NOUN: to loose (λύειν). Like a noun it can be a subject or object, but like a verb it has tense and voice. The Participle is a verbal ADJECTIVE: loosing (λύων). Like an adjective it modifies nouns and must agree in gender/number/case, but like a verb it has tense and voice and can take objects. Both are extremely common in the NT.","key_points":["Infinitive = verbal noun: can be subject, object, or complement of a sentence","Present infinitive: λύειν (to be loosing); Aorist infinitive: λῦσαι (to loose as a whole act)","The article + infinitive is very common: τὸ πιστεύειν = the believing, belief","Participle = verbal adjective: must agree with noun in gender, number, case","Present participle: ongoing action; Aorist participle: prior completed action","Substantival participle: ὁ πιστεύων = the one believing (noun use of participle)","The most famous participle clause: Great Commission — πορευθέντες...μαθητεύσατε (going...make disciples)"],"examples":[{"greek":"ὁ πιστεύων εἰς αὐτόν","translation":"the one believing into him / whoever believes in him","reference":"John 3:16","note":"Present active substantival participle — ὁ πιστεύων functions as a noun: the one who keeps on believing"},{"greek":"πορευθέντες οὖν μαθητεύσατε","translation":"Having gone therefore, make disciples","reference":"Matthew 28:19","note":"Aorist passive participle (going, having gone) + aorist imperative (make disciples). The going is prior to and assumed; the command is the making of disciples"},{"greek":"δεῖ αὐτὸν ἐγερθῆναι","translation":"It is necessary for him to be raised","reference":"John 20:9","note":"Infinitive as subject of δεῖ (it is necessary). The aorist passive infinitive expresses the resurrection"}],"tables":[{"title":"Present Active Participle: λύων","headers":["Case","Masc","Fem","Neut"],"rows":[["Nom Sg","λύων","λύουσα","λῦον"],["Gen Sg","λύοντος","λυούσης","λύοντος"],["Dat Sg","λύοντι","λυούσῃ","λύοντι"],["Acc Sg","λύοντα","λύουσαν","λῦον"]]},{"title":"Participle vs Infinitive","headers":["Verbal","Type","Agrees with","Example"],"rows":[["Participle","Verbal adjective","Noun (gender/number/case)","ὁ πιστεύων (the believing one)"],["Infinitive","Verbal noun","Nothing (indeclinable)","τὸ πιστεύειν (the believing/belief)"]]}],"practice":[{"type":"identify","question":"What is the key difference between a Greek Participle and an Infinitive?","answer":"Participle = verbal adjective (agrees with a noun in gender/number/case); Infinitive = verbal noun (indeclinable)"},{"type":"choice","question":"John 3:16 uses ὁ πιστεύων (present participle). What does the present tense of the participle indicate?","options":["One-time past belief","Ongoing, continuous believing — it is not a once-only act","Future belief","Belief already completed"],"answer":1},{"type":"choice","question":"Matthew 28:19 — πορευθέντες (aorist participle) + μαθητεύσατε (aorist imperative). What is the relationship between going and making disciples?","options":["Going is the main command","Going is secondary — assumed prior action; making disciples is the main imperative","They are equal commands","Going must precede making disciples in time only"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"that whosoever believeth in him should not perish","note":"ὁ πιστεύων — the believing one (present participle as noun). John''s Gospel consistently uses this present participle for saving faith — it is habitual, ongoing trust, not a momentary decision"},{"ref":"Matthew 28:19","text":"Go ye therefore, and teach all nations","note":"πορευθέντες (aorist participle: having gone/going) + μαθητεύσατε (aorist imperative: make disciples). The going is assumed; the Great Commission''s singular imperative is to make disciples. The participle clarifies the method of the mission"}]'
);

-- LESSON 16: KEY CONJUNCTIONS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  70, 16, 'grammar', 'Key Conjunctions', 'καί δέ ἀλλά γάρ ὅτι ἵνα — Intermediate',
  '{"concept":"Key Greek Conjunctions","symbol":"καί · δέ · ἀλλά · γάρ · ὅτι · ἵνα","difficulty":"Intermediate","overview":"Conjunctions are the joints of Greek sentences — they connect clauses and reveal logical relationships. Greek is rich in conjunctions, each carrying a precise nuance. Recognising conjunctions and their functions is crucial for following the argument of NT letters and the flow of Gospel narratives. Six conjunctions are absolutely essential for NT reading.","key_points":["καί = and, also, even (the most common word in the NT — appears 9,164 times!)","δέ = but, and, now (mild contrast or continuation — sentence-second position)","ἀλλά = but (strong contrast — true adversative)","γάρ = for, because (gives the reason for what was just said — sentence-second)","ὅτι = that, because (introduces content clauses or causal clauses)","ἵνα = in order that, so that (introduces purpose or result clauses — takes subjunctive)","Postpositive conjunctions (δέ, γάρ, οὖν) never appear as first word of their clause"],"examples":[{"greek":"οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι","translation":"I did not come to abolish but to fulfil","reference":"Matthew 5:17","note":"ἀλλά = strong contrast. Jesus sets up a sharp antithesis: NOT abolish — strong stop — BUT fulfil"},{"greek":"ἠγάπησεν γὰρ ὁ θεὸς τὸν κόσμον","translation":"For God so loved the world","reference":"John 3:16","note":"γάρ explains the previous statement. Often the γάρ sentence is the key theological reason that unlocks the paragraph"},{"greek":"ἵνα πιστεύητε ὅτι Ἰησοῦς ἐστιν ὁ Χριστός","translation":"in order that you might believe that Jesus is the Christ","reference":"John 20:31","note":"ἵνα + subjunctive = purpose clause. ὅτι = that (content). John''s purpose statement uses both conjunctions in one sentence"}],"tables":[{"title":"The Six Key Conjunctions","headers":["Conjunction","Basic Meaning","Function","Position"],"rows":[["καί","and / also / even","Coordinates, adds","Any position"],["δέ","but / and / now","Mild contrast or continuation","Postpositive (2nd)"],["ἀλλά","but","Strong contrast","Any position"],["γάρ","for / because","Gives reason","Postpositive (2nd)"],["ὅτι","that / because","Content or cause","Any position"],["ἵνα","in order that","Purpose/result + subjunctive","Any position"]]}],"practice":[{"type":"identify","question":"What is the difference between δέ and ἀλλά?","answer":"δέ is a mild contrast or continuation (and/but/now); ἀλλά is a strong adversative contrast (but — true opposition)"},{"type":"choice","question":"γάρ (for/because) is a postpositive conjunction. What does postpositive mean?","options":["It appears at the end of the sentence","It never appears first in its clause — it is pushed to second position","It appears before the verb","It is very rare"],"answer":1},{"type":"choice","question":"ἵνα always introduces a purpose or result clause. What mood of verb does it always take?","options":["Indicative","Imperative","Infinitive","Subjunctive"],"answer":3}]}',
  '[{"ref":"Matthew 5:17","text":"Think not that I am come to destroy the law, or the prophets: I am not come to destroy, but to fulfil","note":"οὐκ...ἀλλά — not...but (strong contrast). The ἀλλά marks the pivot of the entire statement. Everything after the ἀλλά is what Jesus actually came to do — the grammar directs the theology"},{"ref":"John 3:16","text":"For God so loved the world...","note":"γάρ opens verse 16 (the for of John 3:16). This for connects back to verse 15 and the serpent/bronze snake typology. The γάρ tells us verse 16 is the reason for the preceding promise — the logic of grace"}]'
);

-- LESSON 17: DEMONSTRATIVE PRONOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  71, 17, 'grammar', 'Demonstrative Pronouns', 'οὗτος ἐκεῖνος — This one, that one — Intermediate',
  '{"concept":"Demonstrative Pronouns","symbol":"οὗτος · ἐκεῖνος","difficulty":"Intermediate","overview":"Demonstrative pronouns point out specific persons or things: this/these (near) and that/those (far). Greek has two main demonstratives: οὗτος (this, near — this one here) and ἐκεῖνος (that, far — that one there). Both decline for gender, number, and case like adjectives. Their position relative to the article is distinctive: demonstratives always appear OUTSIDE the article-noun bracket (predicate position), even when used attributively.","key_points":["οὗτος = this / these (near demonstrative — closer to speaker)","ἐκεῖνος = that / those (far demonstrative — further from speaker)","Both decline for gender, number, case — must agree with their noun","Position: always outside the article-noun bracket: οὗτος ὁ ἄνθρωπος or ὁ ἄνθρωπος οὗτος","Used substantivally (as noun): οὗτος = this one/he; ἐκεῖνος = that one/he","οὗτος can refer back to the nearest antecedent; ἐκεῖνος can refer to a more remote one"],"examples":[{"greek":"αὕτη ἐστὶν ἡ ζωὴ ἡ αἰώνιος","translation":"This is eternal life","reference":"John 17:3","note":"αὕτη (feminine nom sg of οὗτος) refers back to eternal life and forwards into the definition. The demonstrative makes the definition emphatic"},{"greek":"ἐκεῖνος ἐμὲ δοξάσει","translation":"He (that one / that Counselor) will glorify me","reference":"John 16:14","note":"ἐκεῖνος used as a pronoun for the Holy Spirit (πνεῦμα, neuter) — but Jesus uses masculine ἐκεῖνος, asserting the Spirit''s personhood"},{"greek":"οὗτός ἐστιν ὁ υἱός μου ὁ ἀγαπητός","translation":"This is my beloved Son","reference":"Matthew 3:17","note":"οὗτός (with accent shift) points directly to Jesus at His baptism. The divine voice singles Him out with the near demonstrative"}],"tables":[{"title":"οὗτος (this) — Selected Forms","headers":["Case","Masc","Fem","Neut"],"rows":[["Nom Sg","οὗτος","αὕτη","τοῦτο"],["Gen Sg","τούτου","ταύτης","τούτου"],["Dat Sg","τούτῳ","ταύτῃ","τούτῳ"],["Acc Sg","τοῦτον","ταύτην","τοῦτο"],["Nom Pl","οὗτοι","αὗται","ταῦτα"]]},{"title":"ἐκεῖνος (that) — Selected Forms","headers":["Case","Masc","Fem","Neut"],"rows":[["Nom Sg","ἐκεῖνος","ἐκείνη","ἐκεῖνο"],["Gen Sg","ἐκείνου","ἐκείνης","ἐκείνου"],["Acc Sg","ἐκεῖνον","ἐκείνην","ἐκεῖνο"],["Nom Pl","ἐκεῖνοι","ἐκεῖναι","ἐκεῖνα"]]}],"practice":[{"type":"identify","question":"What is the neuter nominative singular of οὗτος (this)?","answer":"τοῦτο"},{"type":"choice","question":"In John 16:14, Jesus uses ἐκεῖνος (masculine) for the Spirit (πνεῦμα, neuter). What is the theological significance?","options":["Jesus is confused about grammar","Jesus deliberately uses masculine to assert the Spirit''s personhood over grammatical convention","ἐκεῖνος can be any gender","It is a scribal error"],"answer":1},{"type":"choice","question":"Demonstratives always appear in predicate position relative to the article. Which phrase is correct?","options":["ἡ οὗτος ἀγάπη (article first then demonstrative inside)","οὗτος ἡ ἀγάπη or ἡ ἀγάπη αὕτη (demonstrative outside article-noun bracket)","αὕτη ἡ ἀγάπη only","οὗτος ἀγάπη (no article needed)"],"answer":1}]}',
  '[{"ref":"Matthew 3:17","text":"And lo a voice from heaven, saying, This is my beloved Son, in whom I am well pleased","note":"οὗτός ἐστιν ὁ υἱός μου — This is my Son. The Father uses the near demonstrative οὗτος to single out Jesus at His baptism. The demonstrative points with divine authority at the Person of the Son"},{"ref":"John 16:14","text":"He shall glorify me: for he shall receive of mine, and shall shew it unto you","note":"ἐκεῖνος — that One (the Spirit). Five times in John 14-16 Jesus uses ἐκεῖνος for the Spirit, consistently choosing the masculine demonstrative despite πνεῦμα being neuter. This is Jesus''s own grammar lesson about the Spirit''s personhood"}]'
);

-- LESSON 18: RELATIVE PRONOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  72, 18, 'grammar', 'Relative Pronouns', 'ὅς ἥ ὅ — who, which, that — Intermediate',
  '{"concept":"Relative Pronouns","symbol":"ὅς ἥ ὅ","difficulty":"Intermediate","overview":"Relative pronouns introduce relative clauses — subordinate clauses that describe or identify a noun (the antecedent). In English: the man who came, the word that was spoken, the grace which saves. In Greek, the relative pronoun must agree with its antecedent in GENDER and NUMBER, but takes its CASE from its function within the relative clause — a key distinction from English.","key_points":["ὅς = who/which/that (masculine); ἥ = who/which/that (feminine); ὅ = which/that (neuter)","Relative pronoun AGREES with antecedent in gender and number","Relative pronoun takes its CASE from its role WITHIN the clause (not from the antecedent)","This gender/number agreement + case from function is the key to parsing relative pronouns","Attraction: sometimes the relative is pulled into the case of the antecedent (attraction)","Key NT relative clauses: whosoever (πᾶς ὅς = all who), which (ὅ = that which)"],"examples":[{"greek":"ὃς γὰρ ἐὰν θέλῃ τὴν ψυχὴν αὐτοῦ σῶσαι","translation":"For whosoever will save his life","reference":"Matthew 16:25","note":"ὅς is masculine nominative — subject of θέλῃ within the clause. The antecedent is implied: that person who..."},{"greek":"τὸ εὐαγγέλιον ὃ εὐηγγελισάμην","translation":"the gospel which I preached to you","reference":"1 Corinthians 15:1","note":"ὅ is neuter accusative — object of εὐηγγελισάμην within the clause. Agrees with εὐαγγέλιον (neuter) in gender"},{"greek":"ἡ χάρις...ἡ δοθεῖσά μοι","translation":"the grace that was given to me","reference":"1 Corinthians 15:10","note":"Relative clause with participle. The grace (feminine) which was given — gender agreement with χάρις"}],"tables":[{"title":"Relative Pronoun: ὅς ἥ ὅ","headers":["Case","Masc","Fem","Neut"],"rows":[["Nom Sg","ὅς","ἥ","ὅ"],["Gen Sg","οὗ","ἧς","οὗ"],["Dat Sg","ᾧ","ᾗ","ᾧ"],["Acc Sg","ὅν","ἥν","ὅ"],["Nom Pl","οἵ","αἵ","ἅ"],["Gen Pl","ὧν","ὧν","ὧν"]]},{"title":"Rules for Relative Pronouns","headers":["Rule","Example","Explanation"],"rows":[["Gender/Number agree with antecedent","τὸ εὐαγγέλιον ὃ (neut)","εὐαγγέλιον is neuter → ὅ is neuter"],["Case comes from role in clause","ὃ εὐηγγελισάμην (acc)","ὅ is object of εὐηγγελισάμην → accusative"],["Attraction (exception)","ἀξίως τοῦ εὐαγγελίου οὗ","Pulled into genitive of antecedent"]]}],"practice":[{"type":"identify","question":"A relative pronoun agrees with its antecedent in gender and number. From where does it get its case?","answer":"From its grammatical function within the relative clause itself"},{"type":"choice","question":"In τὸ εὐαγγέλιον ὃ εὐηγγελισάμην (the gospel which I preached), why is ὅ neuter?","options":["Because it is the object of preaching","Because εὐαγγέλιον (its antecedent) is neuter","Because relative pronouns are always neuter","It is a mistake"],"answer":1},{"type":"choice","question":"In the same phrase, why is ὅ accusative?","options":["Because εὐαγγέλιον is accusative","Because relative pronouns are always accusative","Because ὅ is the direct object of εὐηγγελισάμην within the relative clause","Because accusative follows ὅ"],"answer":2}]}',
  '[{"ref":"1 Corinthians 15:1","text":"Moreover, brethren, I declare unto you the gospel which I preached unto you, which also ye have received, and wherein ye stand","note":"τὸ εὐαγγέλιον ὃ εὐηγγελισάμην — the gospel which I preached. Two relative clauses stack up to define the gospel Paul is defending. The relative pronouns identify and anchor the content"},{"ref":"John 4:14","text":"But whosoever drinketh of the water that I shall give him shall never thirst","note":"ὃς δ'' ἂν πίῃ — whoever drinks (relative with ἂν + subjunctive = indefinite relative clause). The open invitation of the relative whosoever echoes John 3:16. Christ''s offer has no qualifier except willingness to drink"}]'
);

